if (! function_exists('ascii_fractal_generator')) {
    function ascii_fractal_generator($fractal = null, $size = null, $fill_char = null, $bg_char = null)
    {
        // ASCII fractal generator
        $fractal=isset($fractal)?(string)$fractal:'sierpinski';
        $size=isset($size)?min(max((int)$size,2),128):32;
        $fill=isset($fill_char)?substr((string)$fill_char,0,1):'#';
        $bg=isset($bg_char)?substr((string)$bg_char,0,1):' ';

        $output='';

        if($fractal==='sierpinski'){
            $rows=min($size,64);
            for($y=$rows-1;$y>=0;$y--){
                $line=str_repeat($bg,$y);
                for($x=0;$x<$rows-$y;$x++){
                    $line.=($x&$y)?$bg:$fill;
                    $line.=$bg;
                }
                $output.=rtrim($line)."\n";
            }
        }elseif($fractal==='cantor'){
            $line=str_repeat($fill,$size);
            for($i=0;$i<min($size,10);$i++){
                $output.=$line."\n";
                $third=max(1,(int)(strlen($line)/3));
                $line=substr($line,0,$third).str_repeat($bg,$third).substr($line,$third*2);
            }
        }elseif($fractal==='tree'){
            $depth=min($size,12);
            $lines=[];
            for($i=0;$i<$depth;$i++){
                $spaces=str_repeat(' ',$depth-$i-1);
                $branch=$i===0?'^':($i%2===0?'/ \\':'/ ___ \\');
                $output.=$spaces.$branch."\n";
            }
        }elseif($fractal==='dragon'){
            $iter=min($size,16);
            $d='R';
            for($i=0;$i<$iter;$i++)$d=str_replace(['X','Y','R','L'],['X+YF','FX-Y','X','Y'],$d);
            $x=0;$y=0;$dx=0;$dy=-1;$pts=[[0,0]];
            foreach(str_split($d)as$c){
                if($c==='F'){$x+=$dx;$y+=$dy;$pts[]=[$x,$y];}
                elseif($c==='+'){$t=$dx;$dx=-$dy;$dy=$t;}
                elseif($c==='-'){$t=$dx;$dx=$dy;$dy=-$t;}
            }
            $mx=min(array_column($pts,0));$my=min(array_column($pts,1));
            $mx=$mx<0?-$mx:0;$my=$my<0?-$my:0;
            $grid=[];
            foreach($pts as$p){$gx=$p[0]+$mx;$gy=$p[1]+$my;$grid[$gy][$gx]=true;}
            for($y=0;$y<=max(array_keys($grid));$y++){
                for($x=0;$x<=max(array_map('strlen',$grid));$x++)
                    $output.=isset($grid[$y][$x])?$fill:$bg;
                $output=substr($output,0,-1)."\n";
            }
        }

        return['success'=>true,'fractal'=>$fractal,'size'=>$size,'output'=>$output];
    }
